import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return 5 G processing fee for an empty item list");
    it.todo("should return base premium plus processing fee for a single sword");
    it.todo("should return base premium plus processing fee for a single amulet");
    it.todo("should return base premium plus processing fee for a single staff");
    it.todo("should return base premium plus processing fee for a single potion");
    it.todo("should return base premium plus processing fee for a single component (rune)");
    it.todo("should return combined base premiums plus processing fee for multiple different items");
    it.todo("should apply block discount for exactly 3 alike components");
    it.todo("should NOT apply block discount for 2 alike components");
    it.todo("should NOT apply block discount for 4 alike components");
    it.todo("should apply cursed surcharge (50%) to the cursed item's base premium only");
    it.todo("should apply high-enchantment surcharge (30%) for enchantment >= 5");
    it.todo("should apply loyalty discount (20%) for customer with >= 2 years");
    it.todo("should apply first-insurance surcharge (10%) to every quote");
    it.todo("should apply follow-up contract discount (15%) for second or later quote");
    it.todo("should round premium up in MHPCO's favor");
  });

  describe("claim", () => {
    it.todo("should return payout minus 100 G deductible for standard damage");
    it.todo("should return 50% of damage minus deductible for high-enchantment item (>= 8)");
    it.todo("should return full damage minus deductible for dragon-material item");
    it.todo("should apply 50% rule when both high-enchantment and dragon-material apply");
    it.todo("should apply deductible per damaged item in a multi-item event");
    it.todo("should track remaining cap after a claim");
    it.todo("should cap payout at remaining cap when cap is exhausted");
    it.todo("should round payout down in MHPCO's favor");
  });
});

