  cursed?: boolean;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

export type Policy = {
  items: Item[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSED_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: COMPONENT_BASE_PREMIUM,
};

const withSurcharge = (base: number): number => base + base * FIRST_INSURANCE_SURCHARGE;

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type] ?? 100;
  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE : 0;
  const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE : 0;
  return withSurcharge(base) + cursedSurcharge + enchantmentSurcharge;
};

const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === COMPONENT_BASE_PREMIUM;

const premiumBeforeFee = (items: Item[]): number => {
  if (
    items.length === COMPONENT_BLOCK_SIZE &&
    items.every((item) => item.type === items[0].type) &&
    isComponent(items[0])
  ) {
    return withSurcharge(COMPONENT_BLOCK_PREMIUM);
  }
  return items.reduce((sum, item) => sum + itemPremium(item), 0);
};

export const quote = (
  customer: Customer,
  items: Item[],
  previousQuotes: number
): number => {
  return Math.ceil(premiumBeforeFee(items) + PROCESSING_FEE);
};

export const claim = (
  policy: Policy,
  incident: Incident,
  remainingCap: number
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it("should return 5 G processing fee for an empty item list", () => {
      const customer = { yearsWithMHPCO: 0 };
      expect(quote(customer, [], 0)).toBe(5);
    });
    it("should return base premium plus processing fee for a single sword", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 0, cursed: false }];
      expect(quote(customer, items, 0)).toBe(115);
    });
    it("should return base premium plus processing fee for a single amulet", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }];
      expect(quote(customer, items, 0)).toBe(71);
    });
    it("should return base premium plus processing fee for a single staff", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "staff", material: "oak", enchantment: 0, cursed: false }];
      expect(quote(customer, items, 0)).toBe(93);
    });
    it("should return base premium plus processing fee for a single potion", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "potion", material: "glass", enchantment: 0, cursed: false }];
      expect(quote(customer, items, 0)).toBe(49);
    });
    it("should return base premium plus processing fee for a single component (rune)", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "rune" }];
      expect(quote(customer, items, 0)).toBe(33);
    });
    it("should return combined base premiums plus processing fee for multiple different items", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [
        { type: "sword", material: "steel", enchantment: 0, cursed: false },
        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
      ];
      expect(quote(customer, items, 0)).toBe(181);
    });
    it("should apply block discount for exactly 3 alike components", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "rune" }, { type: "rune" }, { type: "rune" }];
      expect(quote(customer, items, 0)).toBe(71);
    });
    it("should NOT apply block discount for 2 alike components", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "rune" }, { type: "rune" }];
      expect(quote(customer, items, 0)).toBe(60);
    });
    it("should NOT apply block discount for 4 alike components", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }];
      expect(quote(customer, items, 0)).toBe(115);
    });
    it("should apply cursed surcharge (50%) to the cursed item's base premium only", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 3, cursed: true }];
      expect(quote(customer, items, 0)).toBe(165);
    });
    it("should apply high-enchantment surcharge (30%) for enchantment >= 5", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 5, cursed: false }];
      expect(quote(customer, items, 0)).toBe(145);
    });
    it.todo("should apply loyalty discount (20%) for customer with >= 2 years");
    it.todo("should apply first-insurance surcharge (10%) to every quote");
    it.todo("should apply follow-up contract discount (15%) for second or later quote");
    it.todo("should round premium up in MHPCO's favor");
  });

  describe("claim", () => {
    it.todo("should return payout minus 100 G deductible for standard damage");
    it.todo("should return 50% of damage minus deductible for high-enchantment item (>= 8)");
    it.todo("should return full damage minus deductible for dragon-material item");
    it.todo("should apply 50% rule when both high-enchantment and dragon-material apply");
    it.todo("should apply deductible per damaged item in a multi-item event");
    it.todo("should track remaining cap after a claim");
    it.todo("should cap payout at remaining cap when cap is exhausted");
    it.todo("should round payout down in MHPCO's favor");
  });
});

