export type Customer = {
  yearsWithMHPCO: number;
};

export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

export type Policy = {
  items: Item[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSED_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: COMPONENT_BASE_PREMIUM,
};

const withSurcharge = (base: number): number => base + base * FIRST_INSURANCE_SURCHARGE;

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type] ?? 100;
  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE : 0;
  const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE : 0;
  return withSurcharge(base) + cursedSurcharge + enchantmentSurcharge;
};

const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === COMPONENT_BASE_PREMIUM;

const premiumBeforeFee = (items: Item[]): number => {
  if (
    items.length === COMPONENT_BLOCK_SIZE &&
    items.every((item) => item.type === items[0].type) &&
    isComponent(items[0])
  ) {
    return withSurcharge(COMPONENT_BLOCK_PREMIUM);
  }
  return items.reduce((sum, item) => sum + itemPremium(item), 0);
};

const LOYALTY_THRESHOLD = 2;
const LOYALTY_DISCOUNT = 0.2;

const policyBasePremium = (items: Item[]): number =>
  items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 100), 0);

export const quote = (
  customer: Customer,
  items: Item[],
  previousQuotes: number
): number => {
  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBasePremium(items) * LOYALTY_DISCOUNT : 0;
  return Math.ceil(premiumBeforeFee(items) - loyaltyDiscount + PROCESSING_FEE);
};

export const claim = (
  policy: Policy,
  incident: Incident,
  remainingCap: number
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

