export type Customer = {
  yearsWithMHPCO: number;
};

export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

export type Policy = {
  items: Item[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSED_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: COMPONENT_BASE_PREMIUM,
};

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 100;

const withFirstInsuranceSurcharge = (base: number): number => base + base * FIRST_INSURANCE_SURCHARGE;

const itemPremium = (item: Item): number => {
  const base = basePremiumFor(item);
  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE : 0;
  const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE : 0;
  return withFirstInsuranceSurcharge(base) + cursedSurcharge + enchantmentSurcharge;
};

const isComponent = (item: Item): boolean => basePremiumFor(item) === COMPONENT_BASE_PREMIUM;

const premiumBeforeFee = (items: Item[]): number => {
  if (
    items.length === COMPONENT_BLOCK_SIZE &&
    items.every((item) => item.type === items[0].type) &&
    isComponent(items[0])
  ) {
    return withFirstInsuranceSurcharge(COMPONENT_BLOCK_PREMIUM);
  }
  return items.reduce((sum, item) => sum + itemPremium(item), 0);
};

const LOYALTY_THRESHOLD = 2;
const LOYALTY_DISCOUNT = 0.2;
const FOLLOW_UP_DISCOUNT = 0.15;

const policyBasePremium = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumFor(item), 0);

export const quote = (
  customer: Customer,
  items: Item[],
  previousQuotes: number
): number => {
  const policyBase = policyBasePremium(items);
  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_DISCOUNT : 0;
  const followUpDiscount = previousQuotes >= 1 ? policyBase * FOLLOW_UP_DISCOUNT : 0;
  return Math.ceil(premiumBeforeFee(items) - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
};

const DEDUCTIBLE = 100;

export const claim = (
  policy: Policy,
  incident: Incident,
  remainingCap: number
): { payout: number; remainingCap: number } => {
  const payout = Math.floor(Math.min(incident.damages[0].amount - DEDUCTIBLE, remainingCap));
  return { payout, remainingCap: remainingCap - payout };
};

content.text:
**Step 1: Naming Evaluation**

```
**Naming Evaluation**:
- `factor`: describes the reimbursement multiplier — but "factor" is generic
- Question: Does "factor" clearly reveal what it represents?
- Assessment: "factor" hides intent — it's specifically a reimbursement rate
- Decision: Rename `factor` to `reimbursementRate`
```

**Step 2: Current APP Mass for `claim`**

```typescript
const DEDUCTIBLE = 100;
const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;

export const claim = (policy, incident, remainingCap) => {
  const damage = incident.damages[0];
  const item = policy.items.find((i) => i.type === damage.itemType)!;
  const factor = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD ? HIGH_ENCHANTMENT_REIMBURSEMENT : 1;
  const payout = Math.floor(Math.min(damage.amount * factor - DEDUCTIBLE, remainingCap));
  return { payout, remainingCap: remainingCap - payout };
};
```

- Constants: `100`, `8`, `0.5`, `0`, `1`, `DEDUCTIBLE`, `HIGH_ENCHANTMENT_CLAIM_THRESHOLD`, `HIGH_ENCHANTMENT_REIMBURSEMENT` = 8
- Bindings: `policy`, `incident`, `remainingCap`, `damage`, `item`, `i`, `factor`, `payout` = 8
- Invocations: `.find(...)`, `Math.floor(...)`, `Math.min(...)` = 6
- Conditionals: `?? 0`, `>= ... ? ... : 1` = 8
- Loops: `find` (iterates) = 5
- Assignments: `damage =`, `item =`, `factor =`, `payout =` = 24
- Total: 8+8+6+8+5+24 = **59**

**Step 3: Apply Simple Design Rules**

**Rule 1**: ✅ 18 passing

**Rule 2**: `factor` is the weak name — it could be any multiplier. `reimbursementRate` makes the domain intent explicit.

**Rule 3**: No duplication yet. Note that `HIGH_ENCHANTMENT_THRESHOLD` (5, for premiums) and `HIGH_ENCHANTMENT_CLAIM_THRESHOLD` (8, for claims) are intentionally different values for different contexts — not duplication.

**Rule 4**: `damage` binding re-introduced in this phase — it accesses `incident.damages[0]` and is used twice (`damage.itemType`, `damage.amount`). With two uses, it's justified — not a candidate for inlining.

**Step 4: Rename `factor` → `reimbursementRate`**

