    it("should round premium up in MHPCO's favor", () => {
      const customer = { yearsWithMHPCO: 2 };
      const items = [{ type: "rune" }];
      expect(quote(customer, items, 0)).toBe(28);
    });
  });

  describe("claim", () => {
    it("should return payout minus 100 G deductible for standard damage", () => {
